message:
Necesito hacer una migración compleja en desarrollo:
- De: Kinesis en ap-southeast-1 (versión legacy, 5 años de deuda técnica)
- A: VPC con arquitectura moderna en ap-southeast-1
- Sin downtime (SLA 99.95%)
- 2586 GB de datos
- 12 millones de usuarios activos

Aquí está el estado actual del Terraform que gestiona el recurso origen:

```hcl
terraform {
  required_version = ">= 1.5"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
  backend "s3" {
    bucket         = "tfstate-desarrollo-9574"
    key            = "notification-svc/terraform.tfstate"
    region         = "ap-southeast-1"
    encrypt        = true
    dynamodb_table = "tf-lock-desarrollo"
  }
}

provider "aws" {
  region = "ap-southeast-1"
  default_tags {
    tags = {
      Environment = "desarrollo"
      Service     = "notification-svc"
      ManagedBy   = "terraform"
    }
  }
}

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "5.1.2"

  name = "notification-svc-desarrollo-vpc"
  cidr = "10.0.0.0/16"

  azs             = ["ap-southeast-1a", "ap-southeast-1b", "ap-southeast-1c"]
  private_subnets = ["10.208.1.0/24", "10.194.2.0/24", "10.217.3.0/24"]
  public_subnets  = ["10.34.101.0/24", "10.88.102.0/24", "10.73.103.0/24"]

  enable_nat_gateway   = true
  single_nat_gateway   = true
  enable_dns_hostnames = true

  tags = {
    "kubernetes.io/cluster/notification-svc-desarrollo" = "shared"
  }
}

module "eks" {
  source  = "terraform-aws-modules/eks/aws"
  version = "20.0.0"

  cluster_name    = "notification-svc-desarrollo"
  cluster_version = "1.31"

  vpc_id     = module.vpc.vpc_id
  subnet_ids = module.vpc.private_subnets

  cluster_endpoint_public_access = true

  eks_managed_node_groups = {
    general = {
      min_size       = 3
      max_size       = 5
      desired_size   = 5
      instance_types = ["c5.xlarge"]

      labels = {
        role = "general"
      }
    }

    spot = {
      min_size       = 0
      max_size       = 19
      desired_size   = 2
      instance_types = ["m5.2xlarge",
                        "m4.2xlarge"]
      capacity_type  = "SPOT"
    }
  }

  cluster_addons = {
    coredns = {
      most_recent = true
    }
    kube-proxy = {
      most_recent = true
    }
    vpc-cni = {
      most_recent = true
    }
    aws-ebs-csi-driver = {
      most_recent              = true
      service_account_role_arn = module.ebs_csi_irsa_role.iam_role_arn
    }
  }
}
```

¿Cuál es el plan de migración paso a paso? ¿Cómo testeo cada fase?
¿Cómo hago el cutover final en menos de 24 minutos?
¿Qué rollback plan tengo si algo falla en el paso final?

