- A: CodeBuild con arquitectura moderna en sa-east-1
- Sin downtime (SLA 99.95%)
- 4786 GB de datos
- 165 millones de usuarios activos

Aquí está el estado actual del Terraform que gestiona el recurso origen:

```hcl
terraform {
  required_version = ">= 1.5"
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
  backend "s3" {
    bucket         = "tfstate-producción-1613"
    key            = "payment-service/terraform.tfstate"
    region         = "sa-east-1"
    encrypt        = true
    dynamodb_table = "tf-lock-producción"
  }
}

provider "aws" {
  region = "sa-east-1"
  default_tags {
    tags = {
      Environment = "producción"
      Service     = "payment-service"
      ManagedBy   = "terraform"
    }
  }
}

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "5.1.2"

  name = "payment-service-producción-vpc"
  cidr = "10.121.0.0/16"

  azs             = ["sa-east-1a", "sa-east-1b", "sa-east-1c"]
  private_subnets = ["10.44.1.0/24", "10.70.2.0/24", "10.103.3.0/24"]
  public_subnets  = ["10.36.101.0/24", "10.158.102.0/24", "10.155.103.0/24"]

  enable_nat_gateway   = true
  single_nat_gateway   = false
  enable_dns_hostnames = true

  tags = {
    "kubernetes.io/cluster/payment-service-producción" = "shared"
  }
}

module "eks" {
  source  = "terraform-aws-modules/eks/aws"
  version = "20.0.0"

  cluster_name    = "payment-service-producción"
  cluster_version = "1.31"

  vpc_id     = module.vpc.vpc_id
  subnet_ids = module.vpc.private_subnets

  cluster_endpoint_public_access = true

  eks_managed_node_groups = {
    general = {
      min_size       = 1
      max_size       = 17
      desired_size   = 4
      instance_types = ["m5.xlarge"]

      labels = {
        role = "general"
      }
    }

    spot = {
      min_size       = 0
      max_size       = 11
      desired_size   = 7
      instance_types = ["m5.2xlarge",
                        "m4.2xlarge"]
      capacity_type  = "SPOT"
    }
  }

  cluster_addons = {
    coredns = {
      most_recent = true
    }
    kube-proxy = {
      most_recent = true
    }
    vpc-cni = {
      most_recent = true
    }
    aws-ebs-csi-driver = {
      most_recent              = true
      service_account_role_arn = module.ebs_csi_irsa_role.iam_role_arn
    }
  }
}
```

